          rows.append((subdomain, rule.endpoint, methods, str(rule)))

      if sort == "domain":
          rows.sort(key=lambda x: x[0])
      elif sort == "endpoint":
          rows.sort(key=lambda x: x[1])
      elif sort == "methods":
          rows.sort(key=lambda x: x[2])
      elif sort == "rule":
